choose.when:
SELECT hour AS timePoint, AVG(aqi_avg) AS avgAqi, AVG(pm25_avg) AS avgPm25, MAX(aqi_max) AS maxAqi, MIN(aqi_min) AS minAqi FROM dws_station_hour
station_code = #{stationCode}
GROUP BY hour ORDER BY hour

SELECT CONCAT(year, '-', LPAD(month, 2, '0'), '-', LPAD(day, 2, '0')) AS timePoint, AVG(aqi_avg) AS avgAqi, AVG(pm25_avg) AS avgPm25 FROM dws_station_hour
station_code = #{stationCode}
ORDER BY timePoint DESC LIMIT ${days != null ? days : 30}

choose.otherwise:
SELECT CONCAT(year, '-', LPAD(month, 2, '0')) AS timePoint, AVG(aqi_avg) AS avgAqi, AVG(pm25_avg) AS avgPm25 FROM dws_month_summary
district_code = #{stationCode}
ORDER BY timePoint
